from flask import Flask, jsonify, request
from datetime import datetime
import uuid

app = Flask(__name__)

posts = {}

def make_post(title, content, author):
    return {
        "id": str(uuid.uuid4()),
        "title": title,
        "content": content,
        "author": author,
        "created_at": datetime.utcnow().isoformat() + "Z"
    }

@app.errorhandler(404)
def not_found(e):
    return jsonify({"error": "Not found"}), 404

@app.errorhandler(400)
def bad_request(e):
    return jsonify({"error": str(e)}), 400

@app.route("/posts", methods=["GET"])
def get_posts():
    page = int(request.args.get("page", 1))
    limit = int(request.args.get("limit", 10))
    all_posts = sorted(posts.values(), key=lambda p: p["created_at"], reverse=True)
    start = (page - 1) * limit
    return jsonify({
        "posts": all_posts[start:start+limit],
        "total": len(all_posts),
        "page": page,
        "limit": limit
    })

@app.route("/posts/<post_id>", methods=["GET"])
def get_post(post_id):
    post = posts.get(post_id)
    if not post:
        return jsonify({"error": "Post not found"}), 404
    return jsonify(post)

@app.route("/posts", methods=["POST"])
def create_post():
    data = request.get_json()
    if not data:
        return jsonify({"error": "Request body required"}), 400
    required = ["title", "content", "author"]
    missing = [f for f in required if not data.get(f)]
    if missing:
        return jsonify({"error": f"Missing fields: {', '.join(missing)}"}), 400
    post = make_post(data["title"], data["content"], data["author"])
    posts[post["id"]] = post
    return jsonify(post), 201

@app.route("/posts/<post_id>", methods=["PUT"])
def update_post(post_id):
    post = posts.get(post_id)
    if not post:
        return jsonify({"error": "Post not found"}), 404
    data = request.get_json() or {}
    for field in ["title", "content", "author"]:
        if field in data:
            post[field] = data[field]
    post["updated_at"] = datetime.utcnow().isoformat() + "Z"
    return jsonify(post)

@app.route("/posts/<post_id>", methods=["DELETE"])
def delete_post(post_id):
    if post_id not in posts:
        return jsonify({"error": "Post not found"}), 404
    del posts[post_id]
    return jsonify({"deleted": True, "id": post_id})

if __name__ == "__main__":
    app.run(debug=True, port=5000)

