#!/usr/bin/env node
const fs = require('fs');
const path = require('path');

function parseCSV(text) {
  const lines = text.replace(/\r\n/g, '\n').replace(/\r/g, '\n').trim().split('\n');
  if (!lines.length) return [];
  const parseRow = (line) => {
    const fields = []; let cur = ''; let inQuote = false;
    for (let i = 0; i < line.length; i++) {
      const ch = line[i];
      if (ch === '"') {
        if (inQuote && line[i+1] === '"') { cur += '"'; i++; }
        else inQuote = !inQuote;
      } else if (ch === ',' && !inQuote) { fields.push(cur.trim()); cur = ''; }
      else cur += ch;
    }
    fields.push(cur.trim());
    return fields;
  };
  const headers = parseRow(lines[0]);
  const rows = [];
  for (let i = 1; i < lines.length; i++) {
    if (!lines[i].trim()) continue;
    const vals = parseRow(lines[i]);
    const obj = {};
    headers.forEach((h, idx) => {
      const v = vals[idx] ?? '';
      obj[h] = v === '' ? null : isNaN(v) || v === '' ? v : Number(v);
    });
    rows.push(obj);
  }
  return rows;
}

function main() {
  const args = process.argv.slice(2);
  if (!args.length || args[0] === '--help') {
    console.log('Usage: node csv2json.js <input.csv> [output.json] [--pretty]');
    console.log('  --pretty   Format JSON with indentation');
    process.exit(0);
  }
  const inputFile = args[0];
  const pretty = args.includes('--pretty');
  const outputFile = args.find(a => a.endsWith('.json')) || inputFile.replace(/\.csv$/i, '.json');
  if (!fs.existsSync(inputFile)) {
    console.error(`Error: File not found: ${inputFile}`); process.exit(1);
  }
  try {
    const csv = fs.readFileSync(inputFile, 'utf-8');
    const data = parseCSV(csv);
    const json = pretty ? JSON.stringify(data, null, 2) : JSON.stringify(data);
    fs.writeFileSync(outputFile, json, 'utf-8');
    console.log(`Converted ${data.length} rows`);
    console.log(`Output: ${path.resolve(outputFile)}`);
    if (data.length) console.log(`Fields: ${Object.keys(data[0]).join(', ')}`);
  } catch (err) {
    console.error('Error:', err.message); process.exit(1);
  }
}

main();

