        {/* Messages */}
        <div style={{ flex:1, overflowY:'auto', padding:'1.5rem', display:'flex', flexDirection:'column', gap:'8px' }}>
          {msgs.map(m => (
            <div key={m.id} style={{ display:'flex', justifyContent: m.from==='me'?'flex-end':'flex-start' }}>
              <div style={{ maxWidth:'68%', padding:'0.65rem 1rem', borderRadius: m.from==='me'?'18px 18px 4px 18px':'18px 18px 18px 4px', background: m.from==='me'?'#6c63ff':'white', color: m.from==='me'?'white':'#1f2937', boxShadow:'0 1px 4px rgba(0,0,0,0.08)', fontSize:'0.92rem', lineHeight:1.5 }}>
                {m.text}
                <div style={{ fontSize:'0.72rem', opacity:0.6, marginTop:3, textAlign:'right' }}>{m.time}</div>
              </div>
            </div>
          ))}
          {typing && (
            <div style={{ display:'flex', justifyContent:'flex-start' }}>
              <div style={{ background:'white', padding:'0.65rem 1rem', borderRadius:'18px 18px 18px 4px', boxShadow:'0 1px 4px rgba(0,0,0,0.08)', color:'#9ca3af', fontSize:'0.85rem' }}>typing...</div>
            </div>
          )}
          <div ref={endRef}/>
        </div>
        {/* Input */}
        <div style={{ background:'white', padding:'1rem 1.5rem', borderTop:'1px solid #e5e7eb', display:'flex', gap:'10px' }}>
          <input value={input} onChange={e => setInput(e.target.value)} onKeyDown={e => e.key==='Enter' && send()} placeholder={`Message ${activeContact.name}...`} style={{ flex:1, padding:'0.75rem 1rem', border:'2px solid #e5e7eb', borderRadius:'12px', fontSize:'0.95rem', outline:'none', background:'#f9fafb' }}/>
          <button onClick={send} style={{ padding:'0.75rem 1.2rem', background: input.trim()?'#6c63ff':'#e5e7eb', color: input.trim()?'white':'#9ca3af', border:'none', borderRadius:'12px', cursor: input.trim()?'pointer':'default', fontWeight:700, fontSize:'1rem', transition:'all 0.2s' }}>Send</button>
        </div>
      </div>
    </div>
  );
}
